%[text] ## Sine Wave Demo
%[text] This plots a sine wave
fs = 1000; % sampling frequency (Hz)
dur = 1; % signal duration (seconds)
f0 = 4; % sinusoid frequency (Hz)
t = (0:1/fs:dur)'; % time vector
signal = sin(2*pi*f0*t);

plot(t,signal); %[output:64421472]


